// repository.ts
interface HasId {
  id: string;
}

export class Repository<T extends HasId> {
  async findById(id: string): Promise<T | null> {
    return this.db.findOne({ id });
  }
  async save(entity: T): Promise<T> {
    return this.db.upsert(entity);
  }
}
